code.Java:
import java.io.*;
public class Main{
    public static void main(String[] args) throws IOException{
        int[] arr = {1,2,3,4,5};
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<arr.length;i++){
            sb.append(arr[i]);
            if(i<arr.length-1) sb.append(' ');
        }
        sb.append('\n');
        System.out.print(sb.toString());
    }
}

